#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* profits = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &profits[i]);
        }
        int* prefixSum = (int*)malloc((N + 1) * sizeof(int));
        prefixSum[0] = 0;
        for (int i = 1; i <= N; i++) {
            prefixSum[i] = prefixSum[i - 1] + profits[i - 1];
        }
        int minAbsSum = INT_MAX;
        int longestSegment = 0;
        int start = 0;
        int end = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = i; j <= N; j++) {
                int segmentSum = prefixSum[j] - prefixSum[i - 1];
                int absSum = abs(segmentSum);
                if (absSum < minAbsSum || (absSum == minAbsSum && j - i + 1 > longestSegment)) {
                    minAbsSum = absSum;
                    longestSegment = j - i + 1;
                    start = i;
                    end = j;
                }
            }
        }
        printf("%d\n", minAbsSum);
        printf("%d %d\n", start, end);
        free(profits);
        free(prefixSum);
    }
    return 0;
}

